template_code:
int lower_bound_custom(const vector<int>& a, int target) {
    int left = 0, right = (int)a.size(); // Search in [left, right)
    while (left < right) {
        int mid = left + (right - left) / 2; // Avoid overflow
        if (a[mid] >= target) {
            right = mid; // mid can still be the first valid index
        } else {
            left = mid + 1; // mid is invalid, remove it
        }
    }
    return left; // First index with a[i] >= target
}

long long binary_search_answer(long long low, long long high) {
    while (low < high) {
        long long mid = low + (high - low) / 2; // Candidate answer
        if (check(mid)) {
            high = mid; // Feasible, try a smaller answer
        } else {
            low = mid + 1; // Infeasible, need a larger answer
        }
    }
    return low; // Minimum feasible answer
}

deep_dive.body:
建圖方式直接決定怎麼枚舉鄰居，常見有三種建模：

**1. 網格圖 → 方向陣列**
把每格 `(r, c)` 當節點，用方向陣列枚舉鄰格：
```cpp
int dr[4] = {-1, 1, 0, 0};
int dc[4] = {0, 0, -1, 1};
for (int k = 0; k < 4; ++k) {
    int nr = r + dr[k], nc = c + dc[k];
    if (nr < 0 || nr >= R || nc < 0 || nc >= C) continue; // 越界
    if (grid[nr][nc] == '#') continue;                    // 障礙
    // 將 (nr, nc) 入隊
}
```
逐行：`dr/dc` 定義上下左右（八方向再加四組對角）；先檢查越界、再檢查是否可走，最後才入隊。

**2. 隱式圖（如單詞接龍）→ 枚舉鄰居 + 雜湊判重**
節點不顯式存在，鄰居由規則生成（改一個字母）。用 `unordered_map/unordered_set` 把字串映射成是否已訪問，邊在枚舉時即時產生。

**3. 狀態圖（如走迷宮帶鑰匙）→ 狀態壓縮**
節點 = `(位置, 已持有鑰匙的 bitmask)`。同一格子在不同鑰匙狀態下是**不同節點**，visited 要開成 `visited[r][c][1 << keys]`，否則會誤判已訪問而漏解。

template_code:
vector<int> bfs(int start, const vector<vector<int>>& graph) {
    vector<int> dist(graph.size(), -1); // -1 means unvisited
    queue<int> q;
    dist[start] = 0; // Source distance is zero
    q.push(start);
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (int v : graph[u]) {
            if (dist[v] != -1) continue; // Each node enters queue once
            dist[v] = dist[u] + 1; // BFS layer increases by one
            q.push(v);
        }
    }
    return dist;
}

void dfs(int u, const vector<vector<int>>& graph, vector<int>& seen) {
    seen[u] = 1; // Mark before visiting neighbors
    for (int v : graph[u]) {
        if (!seen[v]) dfs(v, graph, seen);
    }
}

deep_dive.body:
差分把『多次區間加值』轉成端點上的兩次單點修改，最後一次前綴和還原：
```cpp
// 區間 [l, r] 同加 val，下標從 1 開始
diff[l]     += val;   // 從 l 起多了 val
diff[r + 1] -= val;   // 過了 r 之後抵銷
// 還原：前綴和即為每個位置的最終值
for (int i = 1; i <= n; ++i)
    a[i] = a[i - 1] + diff[i];
```
逐行：`diff[l] += val` 標記從 l 開始增加；`diff[r + 1] -= val` 在 r 之後把增量抵銷；最後對 `diff` 求前綴和，`a[i]` 就是所有操作疊加後的值。

**適用前提**：下標從 1 開始（避免 `r + 1` 為 0）；`r + 1` 不可超界（陣列開到 `n + 2`）；只支援『先全部修改、再查詢』的靜態場景，過程中要查詢就得改用線段樹／樹狀陣列。

template_code:
vector<pair<int, int>> merge_intervals(vector<pair<int, int>> intervals) {
    sort(intervals.begin(), intervals.end()); // Sort by left endpoint first
    vector<pair<int, int>> merged;
    for (auto [l, r] : intervals) {
        if (merged.empty() || merged.back().second < l) {
            merged.push_back({l, r}); // No overlap with previous interval
        } else {
            merged.back().second = max(merged.back().second, r); // Extend coverage
        }
    }
    return merged;
}

vector<long long> difference_apply(int n, vector<array<int, 3>> ops) {
    vector<long long> diff(n + 1);
    for (auto [l, r, delta] : ops) {
        diff[l] += delta; // Range starts gaining delta
        if (r + 1 < n) diff[r + 1] -= delta; // Range stops after r
    }
    for (int i = 1; i < n; ++i) diff[i] += diff[i - 1]; // Prefix restores values
    diff.pop_back();
    return diff;
}

priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
vector<int> dist(n, INF);
dist[source] = 0;
pq.push({0, source}); // Heap stores the best known candidate
while (!pq.empty()) {
    auto [d, u] = pq.top();
    pq.pop();
    if (d != dist[u]) continue; // Lazy deletion for outdated entries
    for (auto [v, w] : graph[u]) {
        if (dist[v] > d + w) {
            dist[v] = d + w; // Found a better path
            pq.push({dist[v], v});
        }
    }
}

int knapsack_01(const vector<int>& weight, const vector<int>& value, int cap) {
    vector<int> dp(cap + 1, 0); // dp[c] is best value with capacity c
    for (int i = 0; i < (int)weight.size(); ++i) {
        for (int c = cap; c >= weight[i]; --c) { // Reverse order prevents reusing item i
            dp[c] = max(dp[c], dp[c - weight[i]] + value[i]);
        }
    }
    return dp[cap];
}

int lis_length(const vector<int>& a) {
    vector<int> tail; // tail[len - 1] is the minimum ending value
    for (int x : a) {
        auto it = lower_bound(tail.begin(), tail.end(), x);
        if (it == tail.end()) tail.push_back(x);
        else *it = x;
    }
    return (int)tail.size();
}

deep_dive.body:
同向雙指針的通用骨架：
```cpp
int left = 0;
for (int right = 0; right < n; ++right) {
    add(a[right]);                  // 把 right 元素加入視窗
    while (window_invalid()) {       // 視窗違反條件就收縮
        remove(a[left]);            // 把 left 元素移出視窗
        ++left;
    }
    ans = max(ans, right - left + 1); // 此時 [left, right] 合法
}
```
逐行：每輪先把 `right` 納入窗口並更新統計；只要窗口非法就從左端移出元素、`left++`，直到重新合法；迴圈結束時 `[left, right]` 是以 right 為右界的最佳窗口，據此更新答案。換成『最短窗口』時，把更新答案的位置移進 while 迴圈內即可。

template_code:
int longest_window(const vector<int>& a, int limit) {
    int left = 0, sum = 0, ans = 0;
    for (int right = 0; right < (int)a.size(); ++right) {
        sum += a[right]; // Expand window by including right
        while (sum > limit) {
            sum -= a[left]; // Shrink until the invariant is restored
            ++left;
        }
        ans = max(ans, right - left + 1); // Window [left, right] is valid
    }
    return ans;
}

deep_dive.body:
帶權並查集在父指標上額外記錄『到父節點的權值』，`find` 時把沿途權值累加成『到根的偏移』，可解食物鏈、差值等式類問題：
```cpp
int find(int x) {
    if (parent[x] == x) return x;
    int root = find(parent[x]);
    rel[x] += rel[parent[x]]; // 把到父的偏移累加成到根的偏移
    parent[x] = root;          // 路徑壓縮
    return root;
}
```
逐行：先遞迴求父的根（此時 `rel[parent[x]]` 已是父到根的偏移）；把 `rel[x]` 累加上父到根的值，得到 x 到根的偏移；再把 x 直接掛到根。`union(a, b, w)`（表示 b − a = w）時，先 find 兩端的根，再依 `rel[a]`、`rel[b]`、`w` 推出兩根之間應設的權值。

template_code:
struct DSU {
    vector<int> parent, size;
    DSU(int n) : parent(n), size(n, 1) {
        iota(parent.begin(), parent.end(), 0); // Every node starts as its own root
    }
    int find(int x) {
        if (parent[x] == x) return x;
        return parent[x] = find(parent[x]); // Path compression
    }
    bool unite(int a, int b) {
        a = find(a);
        b = find(b);
        if (a == b) return false;
        if (size[a] < size[b]) swap(a, b); // Attach smaller tree to larger tree
        parent[b] = a;
        size[a] += size[b];
        return true;
    }
};

deep_dive.body:
LCA 查詢分兩階段，都靠二進位分解：
```cpp
int lca(int u, int v) {
    if (depth[u] < depth[v]) swap(u, v);      // 讓 u 較深
    int diff = depth[u] - depth[v];
    for (int k = 0; k < LOG; ++k)              // 階段一：把 u 提到與 v 同深度
        if (diff >> k & 1) u = up[u][k];
    if (u == v) return u;                       // v 是 u 的祖先
    for (int k = LOG - 1; k >= 0; --k)          // 階段二：高位到低位同步上跳
        if (up[u][k] != up[v][k]) { u = up[u][k]; v = up[v][k]; }
    return up[u][0];                            // 再跳一步即 LCA
}
```
逐行：先確保 u 較深，用 `diff` 的二進位把 u 上提對齊深度；若對齊後相等，v 本身就是 LCA；否則**從高位往低位**同步跳——只在『跳了之後兩者仍不相同』時才跳，保證停在 LCA 正下方，最後 `up[u][0]` 就是 LCA。階段二必須由高位往低位，才能逼近而不越過。

template_code:
const int LOG = 20;
vector<array<int, LOG>> up;
vector<int> depth;

void dfs_lift(int u, int p, const vector<vector<int>>& tree) {
    up[u][0] = p; // Immediate parent
    for (int k = 1; k < LOG; ++k) {
        up[u][k] = up[up[u][k - 1]][k - 1]; // Jump twice by 2^(k-1)
    }
    for (int v : tree[u]) {
        if (v == p) continue;
        depth[v] = depth[u] + 1;
        dfs_lift(v, u, tree);
    }
}

int kth_ancestor(int u, int k) {
    for (int bit = 0; bit < LOG; ++bit) {
        if (k >> bit & 1) u = up[u][bit]; // Apply binary decomposition
    }
    return u;
}

deep_dive.body:
單調棧題的關鍵在『何時記錄、何時結算』。以柱狀圖最大矩形為例，棧內保持下標對應高度遞增：
```cpp
stack<int> st;                 // 存下標，對應高度遞增
for (int i = 0; i <= n; ++i) {
    int h = (i == n) ? 0 : height[i];   // 末尾補 0 強制清空棧
    while (!st.empty() && height[st.top()] > h) {
        int top = st.top(); st.pop();
        int left = st.empty() ? -1 : st.top();         // 左邊界：新棧頂
        ans = max(ans, height[top] * (i - left - 1));  // 右邊界即 i
    }
    st.push(i);
}
```
逐行：遇到比棧頂矮的 `h`，代表棧頂柱子的『右邊第一個更矮』就是 i，於是**出棧時結算**——以 `height[top]` 為高、寬度 `(i - left - 1)`（左邊界是出棧後的新棧頂）。末尾補一個高度 0 確保所有柱子都被結算。記住順序：**入棧時只記下標，面積一律在出棧時計算**。

template_code:
vector<int> next_greater(const vector<int>& a) {
    vector<int> ans(a.size(), -1), st;
    for (int i = 0; i < (int)a.size(); ++i) {
        while (!st.empty() && a[st.back()] < a[i]) {
            ans[st.back()] = i; // Current i is the first greater element
            st.pop_back();
        }
        st.push_back(i); // Indices in stack have decreasing values
    }
    return ans;
}

vector<int> sliding_max(const vector<int>& a, int k) {
    deque<int> dq;
    vector<int> ans;
    for (int i = 0; i < (int)a.size(); ++i) {
        while (!dq.empty() && dq.front() <= i - k) dq.pop_front(); // Remove expired index
        while (!dq.empty() && a[dq.back()] <= a[i]) dq.pop_back(); // Remove dominated values
        dq.push_back(i);
        if (i >= k - 1) ans.push_back(a[dq.front()]);
    }
    return ans;
}

deep_dive.body:
區間修改若每次都遞迴改到葉子是 O(n)，懶標記的做法是『改到完全覆蓋的節點就停手、打個標記』，等之後真的要訪問其子節點時才把標記下推：
```cpp
void pushdown(int node, int len) {
    if (lazy[node] == 0) return;
    long long t = lazy[node];
    lazy[2*node]   += t; sum[2*node]   += t * (len - len/2); // 左子
    lazy[2*node+1] += t; sum[2*node+1] += t * (len/2);       // 右子
    lazy[node] = 0;       // 標記已下放，清空
}
```
逐行：若無待下推標記直接返回；否則把標記累加到左右子節點的 `lazy`，並依各自長度更新其 `sum`；最後清空本節點標記。**為何不能直接改完就算？** 若只更新當前節點的 `sum` 而不在進入子樹前下推，後續對子區間的查詢會讀到尚未套用本次修改的舊值——下推就是在『訪問子節點之前』補上這筆延遲更新。

template_code:
struct Fenwick {
    int n;
    vector<long long> bit;
    Fenwick(int n) : n(n), bit(n + 1, 0) {}
    void add(int index, long long delta) {
        for (++index; index <= n; index += index & -index) {
            bit[index] += delta; // Update all ranges covering index
        }
    }
    long long sum_prefix(int index) {
        long long ans = 0;
        for (++index; index > 0; index -= index & -index) {
            ans += bit[index]; // Collect disjoint prefix blocks
        }
        return ans;
    }
    long long range_sum(int left, int right) {
        return sum_prefix(right) - (left ? sum_prefix(left - 1) : 0);
    }
};
